window.PACTO.acts["dec_framw-2008-977"]={"label": "DECISIONE QUADRO 2008/977/GAI DEL CONSIGLIO", "short": "Dec. quadro 977/2008", "file": "ext-dec_framw-2008-977.html", "external": true, "version": "originale GU", "eurlex": "https://eur-lex.europa.eu/eli/dec_framw/2008/977/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Oggetto e ambito di applicazione", "anchor": "art_1", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L’oggetto della presente decisione quadro è assicurare un elevato livello di protezione dei diritti e delle libertà fondamentali delle persone fisiche, in particolare del diritto alla vita privata, riguardo al trattamento dei dati personali nell’ambito della cooperazione giudiziaria e di polizia in materia penale di cui al titolo VI del trattato sull’Unione europea, garantendo nel contempo un elevato livello di sicurezza pubblica.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Conformemente alla presente decisione quadro, gli Stati membri proteggono i diritti e le libertà fondamentali delle persone fisiche, in particolare il diritto alla vita privata, quando, ai fini della prevenzione, dell’indagine, dell’accertamento e del perseguimento dei reati o dell’esecuzione delle sanzioni penali, i dati personali:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sono o sono stati trasmessi o resi disponibili tra Stati membri;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sono o sono stati trasmessi o resi disponibili dagli Stati membri ad autorità o a sistemi d’informazione istituiti in base al titolo VI del trattato sull’Unione europea; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sono o sono stati trasmessi o resi disponibili alle competenti autorità degli Stati membri da autorità o sistemi d’informazione istituiti in base al trattato sull’Unione europea o al trattato che istituisce la Comunità europea.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   La presente decisione quadro si applica al trattamento di dati personali, interamente o parzialmente automatizzato, nonché al trattamento non automatizzato di dati personali figuranti o destinati a figurare negli archivi.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   La presente decisione quadro lascia impregiudicati gli interessi fondamentali della sicurezza nazionale e specifiche attività di informazione nel settore della sicurezza nazionale.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   La presente decisione quadro non osta a che gli Stati membri prevedano, per la protezione dei dati personali raccolti o trattati a livello nazionale, garanzie più elevate di quelle stabilite nella presente decisione quadro.</p>\n</div>"]]}, "2": {"label": "Articolo 2", "heading": "Definizioni", "anchor": "art_2", "frags": [[null, "<p class=\"oj-normal\">Ai fini della presente decisione quadro, si intende per:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«dati personali» qualsiasi informazione concernente una persona fisica identificata o identificabile («persona interessata»); si considera identificabile la persona che può essere identificata, direttamente o indirettamente, in particolare mediante riferimento a un numero di identificazione o a uno o più elementi caratteristici della sua identità fisica, fisiologica, psichica, economica, culturale o sociale;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«trattamento di dati personali» e «trattamento» qualsiasi operazione o insieme di operazioni compiute con o senza l’ausilio di processi automatizzati e applicate a dati personali, come raccolta, registrazione, organizzazione, memorizzazione, adattamento o modifica, estrazione, consultazione, uso, comunicazione mediante trasmissione, diffusione o qualsiasi altra forma di messa a disposizione, raffronto o interconnessione, nonché blocco, cancellazione o distruzione;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«blocco» contrassegno dei dati personali memorizzati con l’obiettivo di limitarne il trattamento in futuro;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«archivio di dati personali» e «archivio» qualsiasi insieme strutturato di dati personali accessibili, secondo criteri determinati, indipendentemente dal fatto che tale insieme sia centralizzato, decentralizzato o ripartito in modo funzionale o geografico;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«incaricato del trattamento» qualsiasi organismo che elabora dati personali per conto del responsabile del trattamento;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«destinatario» qualsiasi organismo che riceve comunicazione di dati;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«consenso della persona interessata» qualsiasi manifestazione di volontà libera, specifica e informata con la quale la persona interessata accetta che i dati personali che la riguardano siano oggetto di un trattamento;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«autorità competenti» agenzie o organismi istituiti mediante atti adottati dal Consiglio ai sensi del titolo VI del trattato sull’Unione europea, nonché autorità giudiziarie, doganali, di polizia e altre autorità competenti degli Stati membri autorizzate dalla legislazione nazionale a trattare dati personali nell’ambito della presente decisione quadro;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«responsabile del trattamento» la persona fisica o giuridica, l’autorità pubblica, il servizio o qualsiasi altro organismo che, da solo o insieme ad altri, determina le finalità e gli strumenti del trattamento di dati personali;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«caratterizzazione» contrassegno dei dati personali memorizzati senza l’obiettivo di limitarne il trattamento in futuro;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">k)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">«anonimizzazione» la modificazione di dati personali in modo che i dati particolari su condizioni personali o materiali non possano più, o possano solo con eccessivo dispendio di tempo, costi e lavoro, essere attribuiti a una persona fisica determinata o determinabile.</p>\n</td>\n</tr>\n</tbody>\n</table>"]]}, "3": {"label": "Articolo 3", "heading": "Principi di legalità, proporzionalità e finalità", "anchor": "art_3", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   I dati personali possono essere raccolti dalle autorità competenti soltanto per finalità specifiche, esplicite e legittime nell’ambito dei loro compiti e possono essere trattati solo per la finalità per la quale sono stati raccolti. Il trattamento dei dati deve essere legale e adeguato, pertinente e non eccessivo rispetto alle finalità per le quali sono stati raccolti.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L’ulteriore trattamento per un’altra finalità è ammesso a condizione che:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">non sia incompatibile con le finalità per le quali i dati sono stati raccolti;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le autorità competenti siano autorizzate a trattare tali dati per dette altre finalità in conformità della normativa a esse applicabile; e</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il trattamento sia necessario e proporzionato a tale altra finalità.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">Le autorità competenti possono inoltre trattare ulteriormente i dati personali trasmessi per finalità storiche, statistiche o scientifiche, a condizione che gli Stati membri forniscano adeguate garanzie, come l’anonimizzazione dei dati.</p>\n</div>"]]}, "4": {"label": "Articolo 4", "heading": "Rettifica, cancellazione e blocco", "anchor": "art_4", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   I dati personali sono rettificati se inesatti e, laddove possibile e necessario, sono completati o aggiornati.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   I dati personali sono cancellati o resi anonimi se non sono più necessari per le finalità per le quali sono stati legalmente raccolti o in seguito legalmente trattati. La presente disposizione non osta all’archiviazione di tali dati in un insieme di dati separato per un periodo adeguato conformemente alla legislazione nazionale.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   I dati personali non vengono cancellati ma solo bloccati se vi sono motivi ragionevoli di ritenere che la cancellazione possa compromettere gli interessi legittimi della persona interessata. I dati bloccati sono trattati solo per lo scopo che ha impedito la loro cancellazione.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Qualora i dati personali figurino in una decisione giudiziaria o in un casellario giudiziario in relazione all’emissione di una decisione giudiziaria, la rettifica, la cancellazione o il blocco sono eseguiti in conformità delle norme nazionali sui procedimenti giudiziari.</p>\n</div>"]]}, "5": {"label": "Articolo 5", "heading": "Fissazione di termini per la cancellazione e l’esame", "anchor": "art_5", "frags": [[null, "<p class=\"oj-normal\">Sono previsti adeguati termini per la cancellazione dei dati personali o per un esame periodico della necessità della memorizzazione dei dati. Misure procedurali garantiscono che tali termini siano rispettati.</p>"]]}, "6": {"label": "Articolo 6", "heading": "Trattamento di categorie particolari di dati", "anchor": "art_6", "frags": [[null, "<p class=\"oj-normal\">Il trattamento di dati personali che rivelano l’origine razziale o etnica, le opinioni politiche, le convinzioni religiose o filosofiche, l’appartenenza sindacale, nonché il trattamento di dati relativi alla salute e alla vita sessuale è ammesso soltanto se strettamente necessario e se la legislazione nazionale prevede adeguate garanzie.</p>"]]}, "7": {"label": "Articolo 7", "heading": "Decisioni individuali automatizzate", "anchor": "art_7", "frags": [[null, "<p class=\"oj-normal\">Una decisione che comporti conseguenze giuridiche negative per la persona interessata o la danneggi significativamente e che sia basata unicamente su un trattamento automatizzato di dati destinati a valutare taluni aspetti della sua personalità è ammessa soltanto se autorizzata da una legge che precisi i provvedimenti atti a salvaguardare gli interessi legittimi della persona interessata.</p>"]]}, "8": {"label": "Articolo 8", "heading": "Verifica della qualità dei dati trasmessi o resi disponibili", "anchor": "art_8", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Le autorità competenti prendono tutte le misure ragionevoli per disporre che i dati personali inesatti, incompleti o non più aggiornati non siano trasmessi o resi disponibili. A tal fine le autorità competenti verificano, per quanto possibile, la qualità dei dati personali prima che questi siano trasmessi o resi disponibili. Se possibile tutte le trasmissioni di dati sono corredate delle informazioni disponibili che consentono allo Stato membro ricevente di valutare il livello di esattezza, completezza, aggiornamento e affidabilità. Se i dati personali sono stati trasmessi senza essere stati richiesti, l’autorità ricevente valuta immediatamente se tali dati siano necessari per lo scopo per il quale sono stati trasmessi.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Qualora risulti che sono stati trasmessi dati inesatti o che sono stati trasmessi dati illegalmente, il destinatario deve esserne informato quanto prima. I dati devono essere rettificati, cancellati o bloccati quanto prima in conformità dell’articolo 4.</p>\n</div>"]]}, "9": {"label": "Articolo 9", "heading": "Termini", "anchor": "art_9", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   All’atto della trasmissione o della messa a disposizione dei dati, l’autorità che trasmette i dati può indicare, in conformità della legislazione nazionale e a norma degli articoli 4 e 5, i termini per la loro conservazione, alla scadenza dei quali il destinatario deve cancellare i dati, bloccarli o esaminare se siano ancora necessari. Questo obbligo non si applica se, alla scadenza dei termini, i dati sono necessari per un’indagine in corso, il perseguimento di reati o l’esecuzione di sanzioni penali.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Qualora l’autorità che trasmette i dati non abbia indicato termini conformemente al paragrafo 1, si applicano i termini di cui agli articoli 4 e 5 per la conservazione dei dati previsti dalla legislazione nazionale dello Stato membro ricevente.</p>\n</div>"]]}, "10": {"label": "Articolo 10", "heading": "Registrazione e documentazione", "anchor": "art_10", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Tutte le trasmissioni di dati personali sono registrate o documentate ai fini della verifica della legalità del trattamento dei dati, dell’autocontrollo e per garantire l’integrità e la sicurezza dei dati.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   I registri o la documentazione preparati ai sensi del paragrafo 1 sono trasmessi, su richiesta, all’autorità di controllo competente ai fini del controllo della protezione dei dati. L’autorità di controllo competente utilizza le informazioni solo per il controllo della protezione dei dati e per garantire un trattamento corretto dei dati, nonché la loro integrità e sicurezza.</p>\n</div>"]]}, "11": {"label": "Articolo 11", "heading": "Trattamento dei dati personali trasmessi o resi disponibili da un altro Stato membro", "anchor": "art_11", "frags": [[null, "<p class=\"oj-normal\">Conformemente al disposto dell’articolo 3, paragrafo 2, i dati personali trasmessi o resi disponibili dall’autorità competente di un altro Stato membro possono essere successivamente trattati solo per le seguenti finalità diverse da quelle per le quali sono stati trasmessi o resi disponibili:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la prevenzione, l’indagine, l’accertamento o il perseguimento dei reati o l’esecuzione delle sanzioni penali, diversi da quelli per cui i dati sono stati trasmessi o resi disponibili;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">altre procedure giudiziarie e amministrative direttamente connesse con la prevenzione, l’indagine, l’accertamento e il perseguimento dei reati o l’esecuzione delle sanzioni penali;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la prevenzione di un’immediata e grave minaccia alla sicurezza pubblica; o</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">qualsiasi altra finalità, soltanto previa autorizzazione dello Stato membro che trasmette i dati o con il consenso della persona interessata espresso conformemente alla legislazione nazionale.</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<p class=\"oj-normal\">Le autorità competenti possono inoltre trattare ulteriormente i dati personali trasmessi per finalità storiche, statistiche o scientifiche, a condizione che gli Stati membri forniscano adeguate garanzie, come ad esempio l’anonimizzazione dei dati.</p>"]]}, "12": {"label": "Articolo 12", "heading": "Rispetto delle restrizioni nazionali al trattamento", "anchor": "art_12", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Qualora, in base alla legislazione dello Stato membro che trasmette i dati, si applichino particolari restrizioni di trattamento, in particolari situazioni, allo scambio di dati tra autorità competenti nell’ambito di tale Stato membro, l’autorità che trasmette i dati ne informa il destinatario. Il destinatario provvede affinché tali restrizioni di trattamento siano rispettate.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Qualora applichino il paragrafo 1, gli Stati membri non applicano restrizioni alle trasmissioni di dati ad altri Stati membri o ad agenzie od organismi istituiti ai sensi del titolo VI del trattato sull’Unione europea diverse da quelle applicabili alle analoghe trasmissioni nazionali di dati.</p>\n</div>"]]}, "13": {"label": "Articolo 13", "heading": "Trasferimento alle autorità competenti di paesi terzi o a organismi internazionali", "anchor": "art_13", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri dispongono che i dati personali trasmessi o resi disponibili dall’autorità competente di un altro Stato membro possano essere trasferiti a paesi terzi o a organismi internazionali solo se:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sia necessario per la prevenzione, l’indagine, l’accertamento o il perseguimento dei reati o per l’esecuzione delle sanzioni penali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l’autorità ricevente nel paese terzo o l’organismo internazionale ricevente sono responsabili per la prevenzione, l’indagine, l’accertamento o il perseguimento dei reati o per l’esecuzione delle sanzioni penali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">lo Stato membro presso cui sono stati ottenuti i dati ha acconsentito al trasferimento nel rispetto della legislazione nazionale; e</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il paese terzo o l’organismo internazionale interessati assicurano un adeguato livello di protezione per il trattamento di dati previsto.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il trasferimento senza il consenso preliminare di cui al paragrafo 1, lettera c), non è autorizzato a meno che il trasferimento dei dati sia essenziale per la prevenzione di un’immediata e grave minaccia alla sicurezza pubblica di uno Stato membro o di un paese terzo o agli interessi essenziali di uno Stato membro e se il consenso preliminare non può essere ottenuto in tempo utile. L’autorità competente a dare il consenso è informata senza indugio.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   In deroga al paragrafo 1, lettera d), i dati personali possono essere trasferiti se:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la legislazione nazionale dello Stato membro che trasferisce i dati lo prevede;</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">per interessi specifici legittimi della persona interessata; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">ii)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">per interessi legittimi superiori, soprattutto importanti interessi pubblici; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il paese terzo o l’organismo internazionale ricevente prevedono garanzie ritenute adeguate dallo Stato membro interessato conformemente alla legislazione nazionale.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L’adeguatezza del livello di protezione di cui al paragrafo 1, lettera d), è valutata tenendo conto di tutte le circostanze relative a un’operazione o a un insieme di operazioni di trasferimento dei dati. In particolare sono presi in considerazione la natura dei dati, la finalità e la durata del trattamento previsto, lo Stato d’origine e lo Stato o l’organismo internazionale di destinazione finale dei dati, le norme di diritto, generali o settoriali, vigenti nel paese terzo o nell’organismo internazionale in questione, nonché le regole professionali e le misure di sicurezza che si applicano.</p>\n</div>"]]}, "14": {"label": "Articolo 14", "heading": "Trasmissione a privati negli Stati membri", "anchor": "art_14", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri dispongono che i dati personali ricevuti o resi disponibili dall’autorità competente di un altro Stato membro possano essere trasmessi a privati solo se:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l’autorità competente dello Stato membro presso cui i dati sono stati ottenuti ha acconsentito alla trasmissione nel rispetto della legislazione nazionale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">nessun interesse specifico legittimo della persona interessata impedisce la trasmissione; e</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">in casi particolari il trasferimento è essenziale per l’autorità competente che trasmette i dati a un privato per:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l’adempimento di un compito assegnatole legalmente;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">ii)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la prevenzione, l’indagine, l’accertamento o il perseguimento dei reati o per l’esecuzione delle sanzioni penali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">iii)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la prevenzione di un’immediata e grave minaccia alla sicurezza pubblica; o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">iv)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la prevenzione di un grave danno per i diritti delle persone.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L’autorità competente che trasmette i dati a un privato informa quest’ultimo delle finalità esclusive per le quali i dati possono essere utilizzati.</p>\n</div>"]]}, "15": {"label": "Articolo 15", "heading": "Informazioni su richiesta dell’autorità competente", "anchor": "art_15", "frags": [[null, "<p class=\"oj-normal\">Il destinatario informa, su richiesta, l’autorità competente che ha trasmesso o reso disponibile i dati personali in merito al loro trattamento.</p>"]]}, "16": {"label": "Articolo 16", "heading": "Informazione della persona interessata", "anchor": "art_16", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri provvedono affinché la persona interessata sia informata della raccolta o del trattamento di dati personali da parte delle rispettive autorità competenti, conformemente alla legislazione nazionale.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Qualora siano stati trasmessi o resi disponibili dati personali tra Stati membri, ciascuno Stato membro può chiedere, in conformità delle disposizioni della rispettiva legislazione nazionale di cui al paragrafo 1, che l’altro Stato membro non informi la persona interessata. In tal caso, quest’ultimo Stato membro non informa la persona interessata senza il consenso preliminare dell’altro Stato membro.</p>\n</div>"]]}, "17": {"label": "Articolo 17", "heading": "Diritto di accesso", "anchor": "art_17", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Ogni persona interessata ha il diritto di ottenere, a seguito di richieste presentate a intervalli ragionevoli, senza costrizione e senza ritardi o spese eccessivi:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">almeno conferma del responsabile del trattamento o dell’autorità nazionale di controllo del fatto che dati che la riguardano siano stati trasmessi o resi disponibili, e informazioni sui destinatari o sulle categorie di destinatari cui sono stati comunicati i dati e comunicazione dei dati che sono oggetto di trattamento; oppure</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">almeno conferma dell’autorità nazionale di controllo che sono state effettuate tutte le verifiche necessarie.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Gli Stati membri possono adottare disposizioni legislative che limitano l’accesso alle informazioni di cui al paragrafo 1, lettera a), qualora tale restrizione, tenendo in debito conto gli interessi legittimi della persona interessata, costituisca una misura necessaria e proporzionata:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">per non compromettere indagini, inchieste o procedimenti ufficiali o giudiziari;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">per non compromettere la prevenzione, l’indagine, l’accertamento o il perseguimento dei reati o per l’esecuzione delle sanzioni penali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">per proteggere la sicurezza pubblica;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">per proteggere la sicurezza dello Stato;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">per proteggere la persona interessata o i diritti e le libertà altrui.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Qualsiasi rifiuto o restrizione dell’accesso è comunicato per iscritto alla persona interessata. Contemporaneamente le sono comunicati i motivi di fatto o di diritto sui quali la decisione si basa. Quest’ultima comunicazione può essere omessa qualora sussista uno dei motivi ai sensi del paragrafo 2, lettere da a) a e). In tutti questi casi la persona interessata è informata del fatto che può presentare ricorso presso l’autorità nazionale di controllo competente, un’autorità giudiziaria o un tribunale.</p>\n</div>"]]}, "18": {"label": "Articolo 18", "heading": "Diritto di rettifica, cancellazione o blocco", "anchor": "art_18", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La persona interessata ha diritto a che il responsabile del trattamento adempia i propri obblighi di cui agli articoli 4, 8 e 9 riguardanti la rettifica, la cancellazione o il blocco dei dati personali che gli incombono in virtù della presente decisione quadro. Gli Stati membri stabiliscono se la persona interessata possa far valere questo diritto contro il responsabile del trattamento direttamente o tramite l’autorità nazionale di controllo competente. Se il responsabile del trattamento rifiuta la rettifica, la cancellazione o il blocco, il rifiuto dev’essere comunicato per iscritto alla persona interessata, che deve essere informata circa i mezzi previsti dalla legislazione nazionale per presentare un reclamo o un ricorso. In fase di esame del reclamo o del ricorso, la persona interessata è informata della correttezza o meno dell’agire del responsabile del trattamento. Gli Stati membri possono inoltre disporre che la persona interessata sia informata dall’autorità nazionale di controllo competente che si è proceduto a un esame.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Qualora l’esattezza di un dato personale sia contestato dalla persona interessata e l’esattezza o l’inesattezza non possa essere accertata, si può procedere alla caratterizzazione del dato in questione.</p>\n</div>"]]}, "19": {"label": "Articolo 19", "heading": "Diritto a compensazione", "anchor": "art_19", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Chiunque subisca un danno cagionato da un trattamento illegale o da qualsiasi altro atto incompatibile con le disposizioni nazionali adottate conformemente alla presente decisione quadro ha il diritto di ottenere il risarcimento del danno subíto dal responsabile del trattamento o da altra autorità competente in base alla legislazione nazionale.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Qualora l’autorità competente di uno Stato membro abbia trasmesso dati personali, il destinatario non può, nel contesto della sua responsabilità nei confronti della parte lesa conformemente alla legislazione nazionale, addurre a sua discolpa l’inesattezza dei dati trasmessi. Se il destinatario provvede al risarcimento del danno causato dall’uso di dati impropriamente trasmessi, l’autorità competente che trasmette i dati risarcisce il destinatario dell’importo pagato per tali danni, tenendo conto di eventuali errori commessi dal destinatario.</p>\n</div>"]]}, "20": {"label": "Articolo 20", "heading": "Mezzi di ricorso", "anchor": "art_20", "frags": [[null, "<p class=\"oj-normal\">Fatti salvi i ricorsi amministrativi che possono essere promossi prima che sia adita l’autorità giudiziaria, la persona interessata ha il diritto di proporre un ricorso giurisdizionale in caso di violazione dei diritti garantitile dal diritto nazionale applicabile.</p>"]]}, "21": {"label": "Articolo 21", "heading": "Riservatezza del trattamento", "anchor": "art_21", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Chiunque abbia accesso ai dati personali che rientrano nell’ambito di applicazione della presente decisione quadro può trattare tali dati soltanto se sia membro dell’autorità competente o agisca su istruzione di questa, a meno che non sia tenuto a farlo in virtù di obblighi legali.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Coloro che lavorano per l’autorità competente di uno Stato membro sono vincolati da tutte le disposizioni sulla protezione dei dati che si applicano all’autorità competente in questione.</p>\n</div>"]]}, "22": {"label": "Articolo 22", "heading": "Sicurezza del trattamento", "anchor": "art_22", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri dispongono che le autorità competenti prendano misure tecniche e organizzative adeguate per proteggere i dati personali dalla distruzione accidentale o illegale, dalla perdita accidentale, alterazione, divulgazione o accesso non autorizzati, segnatamente quando il trattamento comporta la trasmissione di dati attraverso una rete o la loro messa a disposizione mediante la concessione di un accesso diretto automatizzato e da qualsiasi altra forma illegittima di trattamento di dati personali, tenendo conto in particolare dei rischi che il trattamento comporta e della natura dei dati da proteggere. Tali misure garantiscono, tenuto conto delle attuali conoscenze tecniche e dei costi dell’applicazione, un livello di sicurezza appropriato rispetto ai rischi presentati dal trattamento e alla natura dei dati da proteggere.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Ciascuno Stato membro adotta, per il trattamento automatizzato dei dati, misure atte a:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">vietare alle persone non autorizzate l’accesso alle attrezzature utilizzate per il trattamento di dati personali (controllo dell’accesso alle attrezzature);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">impedire che supporti di dati possano essere letti, copiati, modificati o asportati da persone non autorizzate (controllo dei supporti di dati);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">impedire che i dati siano inseriti senza autorizzazione e che i dati personali memorizzati siano visionati, modificati o cancellati senza autorizzazione (controllo della memorizzazione);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">impedire che persone non autorizzate utilizzino sistemi di trattamento automatizzato di dati mediante attrezzature per la trasmissione di dati (controllo dell’utente);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">garantire che le persone autorizzate a usare un sistema di trattamento automatizzato di dati abbiano accesso solo ai dati cui si riferisce la loro autorizzazione d’accesso (controllo dell’accesso ai dati);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">garantire la possibilità di verificare e accertare a quali organismi siano stati o possano essere trasmessi o resi disponibili i dati personali utilizzando attrezzature per la trasmissione di dati (controllo della trasmissione);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">garantire la possibilità di verificare e accertare a posteriori quali dati personali sono stati introdotti nei sistemi di trattamento automatizzato dei dati, il momento dell’introduzione e la persona che l’ha effettuata (controllo dell’introduzione);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">impedire che i dati personali possano essere letti, copiati, modificati o cancellati da persone non autorizzate durante i trasferimenti di dati personali o il trasporto di supporti di dati (controllo del trasporto);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">garantire che, in caso di interruzione, i sistemi utilizzati possano essere ripristinati (recupero);</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">j)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">garantire che le funzioni del sistema siano operative, che eventuali errori di funzionamento siano segnalati (affidabilità) e che i dati memorizzati non possano essere falsati da un errore di funzionamento del sistema (autenticità).</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Gli Stati membri dispongono che siano incaricati del trattamento solo organismi in grado di garantire il rispetto delle necessarie misure tecniche e organizzative di cui al paragrafo 1 nonché la conformità alle istruzioni di cui all’articolo 21. L’autorità competente controlla l’operato dell’incaricato del trattamento sotto tali aspetti.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   L’incaricato del trattamento può trattare dati personali soltanto in forza di un atto giuridico o di un contratto scritto.</p>\n</div>"]]}, "23": {"label": "Articolo 23", "heading": "Consultazione preliminare", "anchor": "art_23", "frags": [[null, "<p class=\"oj-normal\">Gli Stati membri provvedono affinché le competenti autorità nazionali di controllo siano consultate prima di trattare dati personali che figureranno in un nuovo archivio di prossima creazione se:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">si tratta delle categorie particolari di dati di cui all’articolo 6; oppure</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il tipo di trattamento, in particolare il ricorso a tecnologie, procedure o meccanismi nuovi, comporta per altri versi rischi specifici per i diritti e le libertà fondamentali della persona interessata, segnatamente per quanto attiene alla tutela della vita privata.</p>\n</td>\n</tr>\n</tbody>\n</table>"]]}, "24": {"label": "Articolo 24", "heading": "Sanzioni", "anchor": "art_24", "frags": [[null, "<p class=\"oj-normal\">Gli Stati membri adottano le misure appropriate per garantire la piena applicazione delle disposizioni della presente decisione quadro e in particolare stabiliscono sanzioni efficaci, proporzionate e dissuasive in caso di violazione delle disposizioni adottate conformemente alla presente decisione quadro.</p>"]]}, "25": {"label": "Articolo 25", "heading": "Autorità nazionali di controllo", "anchor": "art_25", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Ogni Stato membro dispone che una o più autorità pubbliche siano incaricate di fornirgli consulenza e sorvegliare, nel suo territorio, l’applicazione delle disposizioni adottate dagli Stati membri conformemente alla presente decisione quadro. Tali autorità sono pienamente indipendenti nell’esercizio delle loro funzioni.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Ogni autorità di controllo dispone in particolare:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">di poteri investigativi, come la facoltà di accesso ai dati oggetto di trattamento e di raccolta di qualsiasi informazione necessaria all’esercizio della sua funzione di controllo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">di poteri effettivi d’intervento, come quello di formulare pareri prima dell’avvio di trattamenti, e di dar loro adeguata pubblicità, o quello di ordinare il blocco, la cancellazione o la distruzione dei dati, oppure di vietare a titolo provvisorio o definitivo un trattamento, ovvero quello di rivolgere un avvertimento o un monito al responsabile del trattamento o quello di adire i parlamenti o altre istituzioni politiche nazionali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">del potere di promuovere azioni giudiziarie in caso di violazione delle disposizioni nazionali adottate conformemente alla presente decisione quadro ovvero di sottoporre detta violazione all’attenzione delle autorità giudiziarie. Le decisioni dell’autorità di controllo che danno luogo a reclami possono essere oggetto di ricorso.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Chiunque può rivolgersi alle autorità di controllo con un’istanza relativa alla tutela dei diritti e delle libertà personali per quanto riguarda il trattamento dei dati personali. L’interessato è informato dei risultati dell’istanza.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli Stati membri dispongono che i membri e il personale dell’autorità di controllo siano vincolati alle disposizioni vigenti per l’autorità competente in merito alla protezione dei dati personali e siano soggetti, anche dopo la cessazione delle loro attività, all’obbligo del segreto professionale in merito alle informazioni riservate cui hanno accesso.</p>\n</div>"]]}, "26": {"label": "Articolo 26", "heading": "Rapporto con gli accordi conclusi con paesi terzi", "anchor": "art_26", "frags": [[null, "<p class=\"oj-normal\">La presente decisione quadro non pregiudica gli obblighi e impegni incombenti agli Stati membri o all’Unione in virtù di accordi bilaterali e/o multilaterali con paesi terzi esistenti al momento dell’adozione della presente decisione quadro.</p>"], [null, "<p class=\"oj-normal\">Nell’applicare tali accordi, il trasferimento a un paese terzo dei dati personali ottenuti da un altro Stato membro avviene nel rispetto dell’articolo 13, paragrafo 1, lettera c), o paragrafo 2, a seconda dei casi.</p>"]]}, "27": {"label": "Articolo 27", "heading": "Valutazione", "anchor": "art_27", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Entro il 27 novembre 2013, gli Stati membri comunicano alla Commissione le rispettive disposizioni nazionali adottate per conformarsi pienamente alla presente decisione quadro, con particolare riguardo alle disposizioni che devono essere rispettate già al momento della raccolta dei dati. La Commissione valuta segnatamente le implicazioni di tali disposizioni per l’ambito di applicazione della presente decisione quadro di cui all’articolo 1, paragrafo 2.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   A distanza di un anno, la Commissione riferisce al Parlamento europeo e al Consiglio in merito ai risultati della valutazione di cui al paragrafo 1, corredando la sua relazione delle opportune proposte di modifica della presente decisione quadro.</p>\n</div>"]]}, "28": {"label": "Articolo 28", "heading": "Rapporto con altri atti dell’Unione adottati in precedenza", "anchor": "art_28", "frags": [[null, "<p class=\"oj-normal\">Qualora in atti adottati conformemente al titolo VI del trattato sull’Unione europea anteriormente alla data di entrata in vigore della presente decisione quadro e che disciplinano lo scambio di dati personali tra Stati membri o l’accesso delle autorità designate dagli Stati membri ai sistemi d’informazione creati in virtù del trattato che istituisce la Comunità europea siano state introdotte condizioni specifiche relative all’utilizzo di tali dati da parte dello Stato membro ricevente, queste prevalgono sulle disposizioni della presente decisione quadro relative all’utilizzo dei dati personali trasmessi o resi disponibili da un altro Stato membro.</p>"]]}, "29": {"label": "Articolo 29", "heading": "Attuazione", "anchor": "art_29", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Gli Stati membri adottano le misure necessarie per conformarsi alle disposizioni della presente decisione quadro anteriormente al 27 novembre 2010.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Entro tale data gli Stati membri trasmettono al segretariato generale del Consiglio e alla Commissione il testo delle disposizioni inerenti al recepimento nella legislazione nazionale degli obblighi imposti dalla presente decisione quadro e le informazioni relative all’autorità o alle autorità di controllo di cui all’articolo 25. Sulla base di una relazione redatta a partire da tali informazioni dalla Commissione, il Consiglio esamina entro il 27 novembre 2011 in quale misura gli Stati membri si siano conformati alla presente decisione quadro.</p>\n</div>"]]}, "30": {"label": "Articolo 30", "heading": "Entrata in vigore", "anchor": "art_30", "frags": [[null, "<p class=\"oj-normal\">La presente decisione quadro entra in vigore il ventesimo giorno successivo alla pubblicazione nella <span class=\"oj-italic\">Gazzetta ufficiale dell’Unione europea</span>.</p>"]]}}, "recitals": {}};